import { task } from "@trigger.dev/sdk";

export const syncWorkspaceUsage = task({
  id: "sync-workspace-usage",
  run: async (payload: { workspaceId: string }) => {
    console.log("sync usage", payload.workspaceId);
    return { synced: true, workspaceId: payload.workspaceId };
  },
});

import { tasks } from "@trigger.dev/sdk";
import { NextResponse } from "next/server";

import type { syncWorkspaceUsage } from "@/trigger/example";

export async function POST(request: Request) {
  const payload = await request.json();
  const handle = await tasks.trigger<typeof syncWorkspaceUsage>("sync-workspace-usage", payload);

  return NextResponse.json(handle);
}

import { defineConfig } from "@trigger.dev/sdk";

export default defineConfig({
  project: process.env.TRIGGER_PROJECT_ID ?? "proj_replace_me",
  dirs: ["./apps/web/src/trigger"],
});

const checks = [
  "Install vendor package and configure env",
  "Run the local example path",
  "Add auth, retries, and audit events before production",
];

export default function TriggerdevJobsPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Trigger.dev Jobs</h1>
        <p className="text-muted-foreground">Background tasks with managed runs, retries, and operational visibility.</p>
      </div>
      <div className="grid gap-3">
        {checks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
